class LRUCache {
public:
    LRUCache(int capacity) : capacity_(capacity) {}

    int get(int key) {
        if (cache_.find(key) != cache_.end()) {
            int value = cache_[key]->second;
            list_.erase(cache_[key]);
            list_.emplace_front(key, value);
            cache_[key] = list_.begin();
            return value;
        }
        return -1;
    }

    void put(int key, int value) {
        if (cache_.find(key) != cache_.end()) {
            list_.erase(cache_[key]);
        } else if (list_.size() == capacity_) {
            cache_.erase(list_.rbegin()->first);
            list_.pop_back();
        }
        list_.emplace_front(key, value);
        cache_[key] = list_.begin();
    }

private:
    int capacity_;
    list<pair<int, int>> list_;
    unordered_map<int, list<pair<int, int>>::iterator> cache_;
};
```
